import { takaro, data, checkPermission } from '@takaro/helpers';

async function main() {
    const { player, gameServerId, module: mod } = data;

    // If player has whitelist permission, allow them to stay
    if (checkPermission(data.pog, 'WHITELIST_ACCESS')) {
        return;
    }

    // Player doesn't have permission, kick them
    const kickReason = mod.userConfig.kickMessage || 'You do not have whitelist access';

    await takaro.gameserver.gameServerControllerKickPlayer(gameServerId, player.id, {
        reason: kickReason
    });

    await takaro.gameserver.gameServerControllerSendMessage(gameServerId, {
        message: `${player.name} was kicked: not on the whitelist`
    });
}

await main();

